class Solution {
    public boolean equalFrequency(String word) {
        int[] freq = new int[26];
        for (char c : word.toCharArray()) {
            freq[c - 'a']++;
        }
        for (int i = 0; i < word.length(); i++) {
            char c = word.charAt(i);
            freq[c - 'a']--;
            int count = 0;
            int target = 0;
            for (int f : freq) {
                if (f > 0) {
                    count++;
                    target = f;
                }
                if (count > 1 || (count == 1 && f != 0 && f != target)) {
                    break;
                }
            }
            if (count == 1 && target == 1 || count == 0) {
                return true;
            }
            freq[c - 'a']++;
        }
        return false;
    }
}
